// Script Continued Below
function onChange(control, oldValue, newValue, isLoading, isTemplate) {
	if (isLoading || newValue === '') {
		return;
	}

	// 	RAJ - STRY0063655 - Show and hide Primary Assignee, Assigned Member, Subtask Primary Assignee(s) and Subtask Assigned Member(s).

	// this is a new SUB Task form
	// then hide the Primary Assignee and Assigned Memeber singleton fields.
	if((g_form.isNewRecord())
	&& (g_form.getBooleanValue('u_create_multiple_subtasks') == true ))
	{
		g_form.setDisplay('assigned_to_individual',false);
		g_form.setDisplay('primary_assignee',false);
	}else{
		g_form.setDisplay('assigned_to_individual',true);
		g_form.setDisplay('primary_assignee',true);
	}

	// if this is a new form and the user checks the multiple sub tasks checkbox,
	// then show the Subtask Primary Assignee(s) and the Subtask Assigned Memeber(s) multi select fields.
	if((g_form.isNewRecord())
		&& (g_form.getBooleanValue('u_create_multiple_subtasks') == true))
	{
		g_form.setDisplay('u_subtask_assigned_member_s',true);
		g_form.setDisplay('u_subtask_primary_assignee_s',true);
		g_form.setDisplay('u_create_subtasks_in_serial',true);
		// STRY0074674 - if entering multiple, hide these fields they are not allowed in multiple
		g_form.setDisplay('u_internal_contact_performing_task',false);
		g_form.setDisplay('u_internal_contact',false);

	}

	if((g_form.isNewRecord())
		&& (g_form.getBooleanValue('u_create_multiple_subtasks') == false))
	{
		g_form.setDisplay('u_subtask_assigned_member_s',false);
		g_form.setDisplay('u_subtask_primary_assignee_s',false);
		g_form.setDisplay('u_create_subtasks_in_serial',false);
		// STRY0074603 - if single, show these fields they are allowed in single entry
		g_form.setDisplay('u_internal_contact_performing_task',true);
		g_form.setDisplay('u_internal_contact',true);
	}
}
